/* a program convert characters into rune */

#include <rune.h>
#include <stdio.h>
int main(void)
{
	setrunelocale("zh_TW.BIG5");

	const char* src = "rune\xb4\xfa\xb8\xd5";
	const char* ld = src;

	rune_t rune[256];
	int num = 0;
	while( ( rune[num] = sgetrune( ld, 3, &ld ) ) != 0 )
		num ++;

	for( int c = 0; c < num; c ++ )
		printf( " %02x", rune[c] );
	putchar('\n');

}
